SELECT domain_id, COUNT(concept_id) AS concept_count
FROM concept
GROUP BY domain_id;

SELECT concept_name
FROM concept
WHERE concept_name LIKE '%Diagnosis%';

SELECT AVG(condition_count) AS average_conditions_per_patient
FROM (
    SELECT patient_id, COUNT(condition_occurrence_id) AS condition_count
    FROM condition_occurrence
    GROUP BY patient_id
) AS condition_counts;

SELECT COUNT(DISTINCT concept_name) AS unique_concepts, domain_id, vocabulary_id
FROM concept
GROUP BY domain_id, vocabulary_id;

SELECT COUNT(DISTINCT v.patient_id) AS total_patients_with_visits
FROM visits v
WHERE v.visit_date >= DATE('now', '-1 month');

SELECT concept_id, concept_name, COUNT(*) AS concept_count
FROM concept
GROUP BY concept_id, concept_name;

SELECT AVG(julianday(v.visit_date) - julianday(co.condition_start_date)) AS average_condition_duration
FROM condition_occurrence co
INNER JOIN visits v ON co.visit_id = v.visit_id;
